import{_ as a,o as i,c as l,ai as o,ak as d,al as c}from"./chunks/framework.8XgXCEzo.js";const b=JSON.parse('{"title":"Tbed","description":"","frontmatter":{},"headers":[],"relativePath":"start.md","filePath":"start.md"}'),r={name:"start.md"};function t(n,e,s,h,u,m){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="tbed" tabindex="-1">Tbed <a class="header-anchor" href="#tbed" aria-label="Permalink to “Tbed”">​</a></h1><p>演示网站：<a href="https://tbed.bigjackson.top" target="_blank" rel="noreferrer">https://tbed.bigjackson.top</a></p><p><img src="'+d+'" alt=""><img src="'+c+'" alt=""></p><h2 id="许可协议" tabindex="-1">许可协议 <a class="header-anchor" href="#许可协议" aria-label="Permalink to “许可协议”">​</a></h2><ul><li>本项目采用 Apache License 2.0</li><li>完整文本见 <a href="https://github.com/tud8951/tbed/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a></li></ul><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to “特性”">​</a></h2><ul><li>图片上传（JPG/PNG ≤ 5MB），失败信息友好</li><li>首页“热门/最新”切换；分页：移动端每页 10 张、桌面端每页 21 张</li><li>复制分享链接（包含正确文件后缀），支持下载</li><li>懒加载缩略图与边缘代理 <code>/api/i/:id</code>，加速加载</li><li>点赞计数，前端本地去重</li><li>管理后台：分页、删除、保存点赞、允许上传开关、开启图片过滤开关</li><li>图片过滤（Sightengine）：支持多个账号，后台下拉切换；开启过滤时“先审核再写库与推送”，不合规返回 415</li><li>多图床策略：Telegraph（三域）优先，失败回退 Telegram 直链（过滤通过后执行）</li><li>SEO：已添加 robots.txt 与首页 meta（description/keywords/OG）</li><li>后台显示上传者 IP，并支持点击复制</li></ul><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to “技术栈”">​</a></h2><ul><li>Cloudflare Pages + Functions</li><li>Cloudflare KV（元信息与设置）/ D1（图片索引与点赞）</li><li>Telegram Bot（回退图床与推送）/ Sightengine（图片审核）</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h2><ul><li>本地开发：<code>npm i</code> → <code>npm run dev</code>，本地环境变量写入 <code>.dev.vars</code>（<code>PASSWORD</code>、可选 <code>TGBOT</code>、<code>TGGROUP</code>）</li><li>初始化 D1：进入数据库执行 <a href="/schema.sql.html">d1/schema.sql</a></li><li>绑定：在 Pages 仪表盘添加 Bindings（KV=kv，D1=db），并配置环境变量</li><li>验证：访问 <code>/api/env?test=1</code>、<code>/api/count</code>；进入 <code>/admin</code> 进行基础操作</li></ul><h1 id="部署指南-cloudflare-pages" tabindex="-1">部署指南（Cloudflare Pages） <a class="header-anchor" href="#部署指南-cloudflare-pages" aria-label="Permalink to “部署指南（Cloudflare Pages）”">​</a></h1><h2 id="必要配置" tabindex="-1">必要配置 <a class="header-anchor" href="#必要配置" aria-label="Permalink to “必要配置”">​</a></h2><ul><li>Functions 目录：<code>/functions</code>（无需构建命令）</li><li>Bindings <ul><li>KV Namespace：Binding 名 <code>kv</code></li><li>D1 Database：Binding 名 <code>db</code></li></ul></li><li>Environment Variables <ul><li><code>PASSWORD</code>：管理员后台密码</li><li><code>TGBOT</code>、<code>TGGROUP</code>（可选，用于 Telegram 推送）</li><li><code>SIGHTENGINE_USER</code>、<code>SIGHTENGINE_KEY</code>（可选，支持数组：<code>[&quot;user1&quot;,&quot;user2&quot;]</code>、<code>[&quot;secret1&quot;,&quot;secret2&quot;]</code>）</li></ul></li></ul><h2 id="一次性初始化" tabindex="-1">一次性初始化 <a class="header-anchor" href="#一次性初始化" aria-label="Permalink to “一次性初始化”">​</a></h2><ul><li>打开 D1 数据库 → Query → 执行 <code>d1/schema.sql</code></li></ul><h2 id="路由与接口" tabindex="-1">路由与接口 <a class="header-anchor" href="#路由与接口" aria-label="Permalink to “路由与接口”">​</a></h2><ul><li>页面：<code>/</code> 首页；<code>/admin</code> 管理后台（需 Bearer <code>PASSWORD</code>）</li><li>列表：<code>GET /api/images?sort=hot|latest&amp;limit=20&amp;cursor=...</code></li><li>上传：<code>POST /api/upload</code>（JPG/PNG ≤ 5MB）</li><li>代理：<code>GET /api/i/:id?w=...&amp;h=...&amp;q=...</code></li><li>点赞：<code>POST /api/like</code></li><li>设置：<code>GET /api/settings</code></li><li>管理：<code>GET /api/admin/images</code>、<code>POST /api/admin/delete</code>、<code>GET/POST /api/admin/settings</code></li></ul><h2 id="分页与前端行为" tabindex="-1">分页与前端行为 <a class="header-anchor" href="#分页与前端行为" aria-label="Permalink to “分页与前端行为”">​</a></h2><ul><li>移动端每页 10 张；桌面端每页 21 张</li><li>页码可直接跳转；绑定 D1 可随机访问任意页</li></ul><h2 id="图片过滤-可选" tabindex="-1">图片过滤（可选） <a class="header-anchor" href="#图片过滤-可选" aria-label="Permalink to “图片过滤（可选）”">​</a></h2><ul><li>在后台启用“开启图片过滤”</li><li>多账号：<code>SIGHTENGINE_USER=[&quot;user1&quot;,&quot;user2&quot;]</code>、<code>SIGHTENGINE_KEY=[&quot;secret1&quot;,&quot;secret2&quot;]</code></li><li>当前账号索引存储：KV <code>settings:sightengine_index</code></li></ul><h2 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to “验证”">​</a></h2><ul><li><code>GET /api/env?test=1</code> 查看绑定状态（脱敏）</li><li><code>GET /api/count</code> 查看总图片数量</li></ul><h2 id="本地开发" tabindex="-1">本地开发 <a class="header-anchor" href="#本地开发" aria-label="Permalink to “本地开发”">​</a></h2><ul><li><code>npm i</code>、<code>npm run dev</code></li><li><code>.dev.vars</code> 写入 <code>PASSWORD</code>（以及可选 <code>TGBOT</code>、<code>TGGROUP</code>）</li></ul>',26)])])}const P=a(r,[["render",t]]);export{b as __pageData,P as default};
